WITH per_symbol AS (
  SELECT 'SPY' AS Symbol, MAX("Adj Close") AS max_adj_close_2015 FROM "SPY" WHERE "Date" BETWEEN '2015-01-01' AND '2015-12-31'
)
SELECT * FROM per_symbol;

